import { Chart as ChartJS, ArcElement, Tooltip, Legend } from 'chart.js'
import { Doughnut } from 'react-chartjs-2'
import ChartDataLabels from 'chartjs-plugin-datalabels'
import React, { useState, useEffect } from "react";
import { Link } from 'react-router-dom'
import { API_BASE_URL } from '../../config/config';
import axios from "axios";

ChartJS.register(ArcElement, Tooltip, Legend, ChartDataLabels)

// ✅ Define colors at component level (outside any function)
const CHART_COLORS = [
  '#FF6384', '#36A2EB', '#FFCE56', '#4BC0C0', '#9966FF', '#FF9F40',
  '#8AC926', '#1982C4', '#6A0572', '#118AB2', '#06D6A0', '#FFD166',
  '#E5989B', '#B5838D', '#6D6875', '#FFB4A2', '#C9CBFF', '#FDFFB6',
];

export default function RoundStatistics() {
  const apiUrlRound = API_BASE_URL + "api/user/companydashboard/";
  const storedUsername = localStorage.getItem("SignatoryLoginData");
  const userLogin = storedUsername ? JSON.parse(storedUsername) : null;
  const [postMoneyChartData, setPostMoneyChartData] = useState(null);

  // Add state for dynamic options
  const [postMoneyChartOptions, setPostMoneyChartOptions] = useState({
    responsive: true,
    maintainAspectRatio: false,
    cutout: '60%',
    plugins: {
      legend: { position: 'bottom' },
      datalabels: {
        color: '#092840',
        font: { weight: '600', size: 14 },
        formatter: value => value + '%'
      }
    }
  });

  useEffect(() => {
    getroundChart();
  }, []);

  const getroundChart = async () => {
    let formData = {
      company_id: userLogin.companies[0].id,
    };
    try {
      const res = await axios.post(
        apiUrlRound + "getroundChart",
        formData,
        {
          headers: {
            Accept: "application/json",
            "Content-Type": "application/json",
          },
        }
      );

      var respo = res.data.results;
      const capTable = res.data.cap_table || {
        pre_money: { items: [], totals: {} },
        post_money: { items: [], totals: {} }
      };
      console.log(capTable.post_money)

      if (capTable?.post_money?.items?.length > 0) {
        // ✅ STEP 1: Items ko expand karo - HAR INVESTOR ALAG ROW
        const expandedItems = [];

        capTable.post_money.items.forEach((item, originalIndex) => {
          // INVESTOR TYPE - with array of investors
          if (item.type === 'investor' && Array.isArray(item.investor_details) && item.investor_details.length > 0) {
            // Multiple investors in array - create separate entry for EACH
            item.investor_details.forEach((inv, invIdx) => {
              const shareType = item.share_class_type || '';
              const investorName = `${inv.firstName || ''} ${inv.lastName || ''}`.trim() || inv.name || `Investor ${invIdx + 1}`;

              // Calculate per-investor shares (split equally if not available individually)
              const perInvShares = item.shares ? Math.round(item.shares / item.investor_details.length) : 0;

              expandedItems.push({
                ...item,
                _displayName: `👤 ${investorName}${shareType ? ` (${shareType})` : ''}`,
                _shares: inv.shares || perInvShares,
                _email: inv.email || '',
                _phone: inv.phone || '',
                _originalIndex: originalIndex,
                _type: 'investor',
                _isPrevious: true,
                _roundName: item.round_name,
                _investmentAmount: inv.investment_amount || item.investment_amount,
                _groupId: item.name, // Store group name for reference
              });
            });
          }
          // INVESTOR TYPE - single investor (no array)
          else if (item.type === 'investor') {
            const inv = item.investor_details || {};
            const shareType = item.share_class_type || '';
            const investorName = `${inv.firstName || ''} ${inv.lastName || ''}`.trim() || item.name || 'Investor';

            let icon = '👤';
            if (item.is_new_investment) icon = '🆕';
            if (item.is_converted) icon = '🔄';

            expandedItems.push({
              ...item,
              _displayName: `${icon} ${investorName}${shareType ? ` (${shareType})` : ''}`,
              _shares: item.shares || 0,
              _email: inv.email || item.email || '',
              _phone: inv.phone || item.phone || '',
              _originalIndex: originalIndex,
              _type: 'investor',
              _isNew: item.is_new_investment,
              _isPrevious: item.is_previous,
              _roundName: item.round_name,
              _investmentAmount: item.investment_amount,
            });
          }
          // FOUNDER TYPE
          else if (item.type === 'founder') {
            expandedItems.push({
              ...item,
              _displayName: `${item.founder_code || 'F'} - ${item.name}`,
              _shares: item.shares || 0,
              _email: item.email || '',
              _phone: item.phone || '',
              _originalIndex: originalIndex,
              _type: 'founder',
            });
          }
          // OPTION POOL
          else if (item.type === 'option_pool') {
            expandedItems.push({
              ...item,
              _displayName: 'Employee Option Pool',
              _shares: item.shares || 0,
              _existing_shares: item.existing_shares,
              _new_shares: item.new_shares,
              _originalIndex: originalIndex,
              _type: 'option_pool',
            });
          }
          // PENDING (SAFE)
          else if (item.type === 'pending_group') {
            const investors = item.items || [];

            if (investors.length > 0) {
              investors.forEach(inv => {
                const invDetails = inv.investor_details || {};
                const name = inv.name ||
                  `${invDetails.firstName || ''} ${invDetails.lastName || ''}`.trim() ||
                  'Pending Investor';

                expandedItems.push({
                  ...inv,
                  _displayName: `⏳ ${name} (${item.round_name})`,
                  _shares: 0,
                  _email: invDetails.email || inv.email || '',
                  _phone: invDetails.phone || inv.phone || '',
                  _originalIndex: originalIndex,
                  _type: 'pending',
                  _isPending: true,
                  _groupRoundName: item.round_name,
                  _groupInstrumentType: item.instrument_type,
                  // ✅ investor level se fields lo — group level se nahi
                  investment: parseFloat(inv.investment) || 0,
                  potential_shares: inv.potential_shares || 0,
                  discount_rate: inv.discount_rate || 0,
                  valuation_cap: inv.valuation_cap || 0,
                  conversion_price: inv.conversion_price || 0,
                  interest_rate: inv.interest_rate || 0,
                  years: inv.years || 0,
                  interest_accrued: inv.interest_accrued || 0,
                  total_conversion_amount: inv.total_conversion_amount || parseFloat(inv.investment) || 0,
                  maturity_date: inv.maturity_date || null,
                });
              });
            } else {
              // Fallback — group level
              expandedItems.push({
                ...item,
                _displayName: `⏳ ${item.round_name || 'Pending Investor'}`,
                _shares: 0,
                _email: '',
                _phone: '',
                _originalIndex: originalIndex,
                _type: 'pending',
                _isPending: true,
              });
            }
          }
        });

        // Calculate total shares for percentage
        const totalShares = expandedItems.reduce((sum, item) => sum + (item._shares || 0), 0);

        const postMoneyData = {
          labels: expandedItems.map(item => item._displayName),
          datasets: [{
            label: 'Shares',
            data: expandedItems.map(item => item._shares),
            backgroundColor: expandedItems.map((item, i) =>
              item.type === 'pending' ? '#FFC107' :
                item.type === 'option_pool' ? '#4BC0C0' :
                  item.type === 'founder' ? '#36A2EB' :
                    item._isNew ? '#8AC926' :
                      item._isConverted ? '#9966FF' :
                        CHART_COLORS[i % CHART_COLORS.length] // ✅ Use CHART_COLORS here
            ),
            borderWidth: 1,
          }],
          // ✅ Store expanded items for legend
          _expandedItems: expandedItems,
        };

        setPostMoneyChartData(postMoneyData);

        // ✅ Create dynamic options based on the data
        createDynamicChartOptions(expandedItems, totalShares);
      }
    } catch (err) {
      console.error("Error fetching country list:", err);
    }
  };

  // ✅ Function to create dynamic chart options
  const createDynamicChartOptions = (expandedItems, totalShares) => {
    const dynamicOptions = {
      responsive: true,
      maintainAspectRatio: false,
      cutout: '60%',
      plugins: {
        legend: {
          position: 'bottom',
          labels: {
            font: {
              size: 11
            },
            generateLabels: (chart) => {
              // Custom legend to show only unique types
              const types = {};
              expandedItems.forEach(item => {
                let type = 'Other';
                if (item.type === 'founder') type = 'Founders';
                else if (item.type === 'option_pool') type = 'Option Pool';
                else if (item.type === 'pending') type = 'Pending SAFE';
                else if (item._isNew) type = 'New Investors';
                else if (item._isConverted) type = 'Converted';
                else if (item._isPrevious) type = 'Previous Investors';

                types[type] = (types[type] || 0) + (item._shares || 0);
              });

              return Object.keys(types).map((type, i) => ({
                text: `${type} (${((types[type] / totalShares) * 100).toFixed(2)}%)`,
                fillStyle: CHART_COLORS[i % CHART_COLORS.length], // ✅ Use CHART_COLORS here
                strokeStyle: 'transparent',
                lineWidth: 0,
                hidden: false,
                index: i
              }));
            }
          }
        },
        tooltip: {
          callbacks: {
            label: (context) => {
              const item = expandedItems[context.dataIndex];
              const value = context.raw || 0;
              const percentage = totalShares > 0 ? ((value / totalShares) * 100).toFixed(2) : 0;

              let label = `${context.label}: ${value.toLocaleString()} shares (${percentage}%)`;

              // Add extra info for different types
              if (item.type === 'founder') {
                label += `\n👤 ${item.email ? `Email: ${item.email}` : ''}`;
              } else if (item.type === 'pending') {
                if (item.investment) {
                  label += `\n💰 Investment: ${item.investment.toLocaleString()}`;
                }
                if (item.discount_rate) {
                  label += `\n🏷️ Discount: ${item.discount_rate}%`;
                }
                if (item.valuation_cap) {
                  label += `\n🎯 Cap: ${item.valuation_cap.toLocaleString()}`;
                }
              } else if (item._investmentAmount) {
                label += `\n💰 Investment: ${item._investmentAmount.toLocaleString()}`;
              }

              return label;
            }
          }
        },
        datalabels: {
          color: '#092840',
          font: {
            weight: '600',
            size: window.innerWidth < 768 ? 10 : 12
          },
          formatter: (value, context) => {
            const percentage = totalShares > 0 ? ((value / totalShares) * 100).toFixed(2) : 0;
            // Only show percentage if it's > 2% to avoid clutter
            return parseFloat(percentage) > 2 ? percentage + '%' : '';
          },
          display: (context) => {
            // Only show labels if chart is not too crowded
            return expandedItems.length < 15;
          }
        }
      },
      // Add animation for better UX
      animation: {
        animateScale: true,
        animateRotate: true
      }
    };

    setPostMoneyChartOptions(dynamicOptions);
  };

  return (
    <div className='investor-reports'>
      <div className='investor-reports__header'>
        <h4>Current Round Statistics</h4>
      </div>

      <div className='investor-reports__list'>
        <div className='round-chart'>
          {postMoneyChartData ? (
            <Doughnut
              data={postMoneyChartData}
              options={postMoneyChartOptions}
            />
          ) : (
            <div>Loading chart data...</div>
          )}
        </div>
      </div>
    </div>
  )
}